VALUES
  ('judicial-f0899a01-moex-00136', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲犯擄人勒贖罪，取得贖金後旋即偷渡出境而被通緝，有關時效之敘述，下列何者錯誤？', '["擄人勒贖罪之追訴時效為30年", "該罪之時效自犯罪成立之日起算", "若甲擄人勒贖致人於死，無追訴權消滅問題", "追訴權之時效因甲逃匿遭通緝而停止進行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00137', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於刑法第132條洩漏國防以外秘密罪，下列敘述何者錯誤？', '["負責採購之公務員甲於採購前洩漏預定單價予廠商乙，構成刑法第132條第1項之罪", "檢察官甲洩漏偵查中之刑事案件資料予不相干之第三人乙，構成刑法第132條第1項之罪", "員警甲洩漏因其公務而知悉之民眾乙戶籍資料，因僅涉及個人資訊，不成立刑法第132條第1項之罪", "員警甲洩漏其所掌管之刑事案件筆錄資料予記者乙，構成刑法第132條第1項之罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00138', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於妨害公務罪，下列敘述何者錯誤？', '["對於公務員依法執行職務時施強暴，係指公務員開始實行其職務時至其行為終了時止，若已經執行職務 完畢，不成立妨害公務罪", "對於公務員依法執行職務時施強暴，係指公務員開始實行其職務時至其行為終了時止，若尚未開始執行 職務，不成立妨害公務罪", "甲對於執行職務之警察乙施以脅迫而妨害公務，但乙沒有理會，繼續執行職務，甲成立妨害公務罪未遂犯", "甲對於執行職務之警察乙施以脅迫而妨害公務，一經實施，妨害公務罪即成立，對於執行職務，已否發 生妨害之結果，在所不問"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00139', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '依通說見解，下列何者非屬刑法第161條第2項之「拘禁處所」？', '["監獄", "看守所", "警察民眾服務中心", "民事管收所"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00140', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲對時局不滿在網站上公開發文，謊稱其已在某未指名的捷運站內放置炸彈，目的是要警告某立法委員， 該貼文遭網友大量轉傳，造成人心惶惶。甲隨後因觸犯刑法第151條恐嚇公眾罪遭移送法辦。下列敘述何 者正確？', '["甲雖係謊稱，但仍屬恐嚇", "甲僅係警告某立法委員，尚不符合以加害生命之事恐嚇公眾", "甲警告的對象係某立法委員而非公眾，故行為客體並非本罪規範對象", "雖人心惶惶，但因甲並未放置炸彈，故不該當「致生危害於公安」要件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00141', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', 'A殺死B，目擊證人甲誤以為是C殺死B，於法院審判時，證人甲具結後陳述「C殺死B」，甲之刑事責任 為何？', '["過失偽證罪", "故意偽證罪", "誣告罪", "甲不成立犯罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00142', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲開車至某路口停等紅燈，被後方乙所駕駛的車輛撞擊。乙因煞車過猛撞擊頭部流血，幸無大礙，甲見乙 僅受輕傷，未作任何處理，立即離開現場。甲成立何罪？', '["過失傷害罪", "遺棄罪", "發生交通事故逃逸罪", "不作為殺人未遂罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00143', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關刑法第195條偽造變造通用貨幣罪，下列何者錯誤？', '["本罪犯罪行為係以無貨幣製造權為前提，故屬於有形偽造", "偽造消費券，不成立本罪", "偽造外國貨幣，成立本罪", "偽造本國貨幣只為自我欣賞收藏，不成立本罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00144', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲因缺錢花用，偷偷進入其父乙書房，竊取乙所有之支票本1本後，拿回自己房中，撕下其中一張支票， 在發票人處偽簽乙姓名，並填載新臺幣 10 萬元及發票年月日後，持該支票欲出門向朋友借款時，為乙發 覺，當場制止。甲觸犯何罪名？', '["竊盜罪及偽造有價證券罪", "竊盜罪及偽造公文書罪", "竊盜罪及偽造貨幣罪", "竊盜罪及行使偽造有價證券罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00145', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於妨害風化罪，下列敘述何者錯誤？', '["單純從事性交易者，不構成刑法上犯罪", "媒介性交易而營利者，不構成刑法上犯罪", "以強暴、脅迫方式使人為性交易而營利者，構成刑法上犯罪", "引誘未滿16歲之人為性交易者，構成刑法上犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
